#include <stdio.h>


struct Knjiga {
    char naziv[40];
    char autor[30];
    int godina;
};


int main() {
    
    struct Knjiga k;
    int n, i;

    FILE *f = fopen("knjige.txt", "w");
    
    if (f == NULL) {
        printf("Greska pri kreiranju datoteke knjige.txt\n");
        return 1;
    }

    printf("Koliko knjiga zelite unijeti: ");
    scanf("%d", &n);

    for (i = 0; i < n; i++) {
        printf("\nKnjiga %d\n", i + 1);

        printf("Naziv: ");
        scanf("%s", k.naziv);

        printf("Autor: ");
        scanf("%s", k.autor);

        printf("Godina izdanja: ");
        scanf("%d", &k.godina);

        fprintf(f, "%s %s %d\n", k.naziv, k.autor, k.godina);
    }

    fclose(f);

    printf("Nova datoteka knjige.txt je kreirana.\n");

    return 0;
}
